@spec config_schema_spec  src=tests/specs/config_schema_spec.lua  loc=474  sha=fe11d27  cases=31
@exercises configManager (h.cm)
@surface   cm:get, cm:set, cm:setContext, cm:remove, cm:assign, cm:getAt, cm:clearTake, cm:setTrack, cm:subscribe, cm:seedGlobalFromDefault
@harness   mk, r._state.takeExt, r._state.trackExt

# Intent
  Pin-tests for configManager's schema enforcement and ownership contract.
  Covers: unknown-key rejection at every API entry; silent prune of unknown
  keys on persistence load; deep-copy at read AND write boundaries so
  callers never alias cm's internal state.

# Cases
  @case 'cm:get on an unknown key raises'  [harness]  @ 14-20
  @case 'cm:set on an unknown key raises'  [harness]  @ 23-28
  @case 'take-tier write with no bound take is a silent no-op (dormant seam)'  [harness]  @ 31-45
  @case 'cm:remove on an unknown key raises'  [harness]  @ 48-53
  @case 'cm:assign rejects updates that contain unknown keys'  [harness]  @ 56-65
  @case 'cm:getAt on an unknown key raises'  [harness]  @ 68-73
  @case 'cm:getAt full-level read does not require a key'  [harness]  @ 76-83
  @case 'schema default surfaces when no level has set the key'  [harness]  @ 96-100
  @case 'null-defaulted keys are declared but return nil'  [harness]  @ 103-115
  @case 'unknown keys in persisted data are pruned on load'  [harness]  @ 126-145
  @case 'cm:get returns a deep copy — caller mutation does not leak'  [harness]  @ 152-163
  @case 'cm:get of a default table returns a fresh table each call'  [harness]  @ 166-173
  @case 'cm:set deep-copies the incoming value — caller mutation after set does not leak'  [harness]  @ 176-186
  @case 'more specific level overrides less specific'  [harness]  @ 193-202
  @case 'a false at a tier shadows a truthy default and a truthy lesser tier'  [harness]  @ 207-220
  @case 'remove at a level falls back to the next less-specific level'  [harness]  @ 223-235
  @case 'transient is the most-specific level (overrides take)'  [harness]  @ 242-253
  @case 'transient writes do not persist across cm reconstruction'  [harness]  @ 256-269
  @case 'clearTake empties take cache; lower tiers and track tier survive'  [harness]  @ 275-290
  @case 'setTrack rebinds the track tier to a different track\'s P_EXT'  [harness]  @ 293-306
  @case 'setTrack is independent of take — take cache stays put'  [harness]  @ 309-316
  @case 'clearTake and setTrack both fire configChanged (keyless)'  [harness]  @ 319-331
  @case 'mergeTiers unions tier tables per sub-key'  [harness]  @ 348-367
  @case 'mergeTiers returns a fresh deep copy'  [harness]  @ 370-384
  @case 'mergeTiers with no tier contributions returns the schema default'  [harness]  @ 387-397
  @case 'mergeTiers default + tier writes union per sub-key'  [harness]  @ 400-408
  @case 'mergeTiers: tier write on a default-named key wins'  [harness]  @ 411-421
  @case 'cm:seedGlobalFromDefault seeds the global library from the catalogue when empty'  [harness]  @ 427-435
  @case 'cm:seedGlobalFromDefault is a no-op once the global library exists'  [harness]  @ 438-445
  @case 'cm:seedGlobalFromDefault seeds tempers from the EDO catalogue'  [harness]  @ 448-455
  @case 'cm fires changes with their level on the broadcast'  [harness]  @ 459-472

